import socket
from datetime import datetime
import threading
import pickle
import math

class Player:
    def __init__(self, id, x, y):
        self.id = id
        self.x = x
        self.y = y

class GameState:
    def __init__(self, players):
        self.players = players
        self.time = datetime.now().strftime("%H:%M:%S")

    def distance(self, player1, player2):
        return math.sqrt((player1.x - player2.x) ** 2 + (player1.y - player2.y) ** 2)

class Server:
    def __init__(self, host='127.0.0.1', port=12345):
        self.host = host
        self.port = port
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.players = {}
        self.clients = []
        self.lock = threading.Lock()

    def broadcast(self, message):
        for client in self.clients:
            client.send(message)

    def handle_client(self, client_socket):
        while True:
            try:
                data = pickle.loads(client_socket.recv(4096))
                if data['type'] == 'join':
                    with self.lock:
                        self.players[data['player']['id']] = data['player']
                        self.clients.append(client_socket)
                elif data['type'] == 'update':
                    player_id = data['player_id']
                    new_position = (data['new_x'], data['new_y'])
                    with self.lock:
                        if player_id in self.players:
                            self.players[player_id].x, self.players[player_id].y = new_position
                            self.broadcast(pickle.dumps(GameState(list(self.players.values()))))
            except Exception as e:
                print(f'Error: {e}')
                break

    def run(self):
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(5)
        while True:
            client_socket, address = self.server_socket.accept()
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

if __name__ == '__main__':
    server = Server()
    server.run()